// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 500
// Define the structure for a tree node
typedef struct Node {
    int data;
    struct Node** children;
    int numChildren;
} Node;
// Function to create a new tree node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->data = data;
    newNode->children = NULL;
    newNode->numChildren = 0;
    return newNode;
}
// Function to add a child to a tree node
void addChild(Node* parent, Node* child) {
    parent->numChildren++;
    parent->children = (Node**) realloc(parent->children, parent->numChildren * sizeof(Node*));
    parent->children[parent->numChildren - 1] = child;
}
// Function to perform DFS and calculate the number of good subtrees
int dfs(Node* node, int* a, int* dp) {
    if (dp[node->data] != -1) return dp[node->data];
    int count = 0;
    for (int i = 0; i < node->numChildren; i++) {
        count += dfs(node->children[i], a, dp);
    }
    if (a[node->data] != -1) count++;
    dp[node->data] = count % MOD;
    return count % MOD;
}
// Function to calculate the digit string D(S)
int calculateDS(Node* node, int* a) {
    int ds = 0;
    ds = ds * 10 + node->data;
    for (int i = 0; i < node->numChildren; i++) {
        ds = ds * 10 + calculateDS(node->children[i], a);
    }
    return ds;
}
// Function to check if a digit string occurs in the recurrent sequence
int checkSequence(int ds, int* a) {
    for (int i = 0; i < 100; i++) {
        if (a[i] == ds) return 1;
    }
    return 0;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node** nodes = (Node**) malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(0);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addChild(nodes[u - 1], nodes[v - 1]);
        }
        int* a = (int*) malloc(100 * sizeof(int));
        for (int i = 0; i < 100; i++) {
            a[i] = -1;
        }
        a[0] = 1;
        for (int i = 1; i < 100; i++) {
            a[i] = a[i - 1] + (a[i - 1] % 10);
        }
        int* dp = (int*) malloc((N + 1) * sizeof(int));
        for (int i = 0; i <= N; i++) {
            dp[i] = -1;
        }
        int count = dfs(nodes[0], a, dp);
        printf("%d\n", count);
        free(nodes);
        free(a);
        free(dp);
    }
    return 0;
}

